import React, { useState } from "react";
import attendanceApi from "../../api/attendanceApi";
import SectionHeader from "../../components/shared/SectionHeader";
import AlertBanner from "../../components/shared/AlertBanner";
import { parseApiError } from "../../utils/apiErrorParser";
import "../../styles/pages.css";

export default function RecordAttendancePage() {
  const [form, setForm] = useState({
    studentEmail: "",
    classId: "",
    date: new Date().toISOString().split("T")[0],
    status: "PRESENT",
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError(""); setSuccess("");
    setLoading(true);
    try {
      await attendanceApi.markAttendance(form);
      setSuccess("Attendance recorded!");
      setForm({ ...form, studentEmail: "" });
    } catch (err) {
      setError(parseApiError(err));
    } finally {
      setLoading(false);
    }
  };

  return (
    <div>
      <SectionHeader title="Mark Attendance" subtitle="POST /teacher/mark-attendance" />
      <div className="page-form">
        <AlertBanner type="error" message={error} onClose={() => setError("")} />
        <AlertBanner type="success" message={success} onClose={() => setSuccess("")} />
        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label>Student Email</label>
            <input type="email" value={form.studentEmail} onChange={(e) => setForm({ ...form, studentEmail: e.target.value })} required disabled={loading} />
          </div>
          <div className="form-group">
            <label>Class ID</label>
            <input value={form.classId} onChange={(e) => setForm({ ...form, classId: e.target.value })} required disabled={loading} />
          </div>
          <div className="form-group">
            <label>Date</label>
            <input type="date" value={form.date} onChange={(e) => setForm({ ...form, date: e.target.value })} required disabled={loading} />
          </div>
          <div className="form-group">
            <label>Status</label>
            <select value={form.status} onChange={(e) => setForm({ ...form, status: e.target.value })} disabled={loading}>
              <option value="PRESENT">Present</option>
              <option value="ABSENT">Absent</option>
              <option value="LATE">Late</option>
            </select>
          </div>
          <button type="submit" className="submit-btn" disabled={loading}>{loading ? "Recording…" : "Mark Attendance"}</button>
        </form>
      </div>
    </div>
  );
}
